contracts/MiningPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title MiningPool
 * @notice MinerHub 鎸栫熆鏍稿績鍚堢害
 * - 鐭垮伐娉ㄥ唽銆佺畻鍔涙洿鏂?
 * - 濂栧姳璁＄畻鍜屽垎閰?
 * - 鎻愬彇鍐峰嵈鏈哄埗
 * - 闃蹭綔寮婃娴?
 */
contract MiningPool is Ownable, ReentrancyGuard {
    // SUPER 浠ｅ竵鍦板潃
    IERC20 public superToken;
    
    // 鎸栫熆鍙傛暟
    uint256 public constant DAILY_EMISSION = 2_847_222 * 10 ** 18;  // 鏃ヤ骇 284.7222 涓?SUPER
    uint256 public constant MIN_HASHRATE = 100;                      // 鏈€灏忕畻鍔涳細0.1 MH/s
    uint256 public constant MAX_HASHRATE = 10_000_000;               // 鏈€澶х畻鍔涳細10 MH/s
    
    // 濂栧姳鍙傛暟
    uint256 public rewardPerHashPerDay = 1 * 10 ** 12;  // 姣忓ぉ姣忓崟浣嶇畻鍔涜幏寰楀鍔?
    uint256 public claimCooldown = 1 days;              // 棰嗗彇鍐峰嵈鏃堕棿
    uint256 public lockupPeriod = 7 days;               // 棣栨鎸栫熆閿佷粨鏈?
    
    // 闅惧害璋冩暣
    uint256 public globalHashrate;
    uint256 public lastDifficultyAdjustment;
    uint256 public difficultyAdjustmentPeriod = 7 days;
    
    // 鐭垮伐淇℃伅缁撴瀯
    struct Miner {
        uint256 hashrate;              // 褰撳墠绠楀姏
        uint256 lastClaimed;           // 涓婃棰嗗彇鏃堕棿
        uint256 pendingReward;         // 寰呴鍙栧鍔?
        uint256 totalClaimed;          // 宸查鍙栨€婚噺
        uint256 registeredTime;        // 娉ㄥ唽鏃堕棿
        bool active;                   // 鏄惁娲昏穬
        uint256 suspiciousScore;       // 鍙枒鍒嗘暟 (0-100)
    }
    
    // 鐭垮伐鏄犲皠 (閽卞寘鍦板潃 -> Miner)
    mapping(address => Miner) public miners;
    mapping(address => bool) public registeredMiners;
    
    // 缁熻鏁版嵁
    uint256 public totalMiners;
    uint256 public totalActiveHashrate;
    uint256 public totalEmitted;
    
    // 浜嬩欢
    event MinerRegistered(address indexed miner, uint256 hashrate);
    event HashrateUpdated(address indexed miner, uint256 oldHashrate, uint256 newHashrate);
    event RewardClaimed(address indexed miner, uint256 amount);
    event DifficultyAdjusted(uint256 newGlobalHashrate);
    event MinerDeactivated(address indexed miner, string reason);
    event RewardParametersUpdated(uint256 newRewardPerHash, uint256 newClaimCooldown);
    event SuspiciousActivityDetected(address indexed miner, uint256 score, string reason);
    
    constructor(address _superToken) {
        require(_superToken != address(0), "Invalid SUPER token address");
        superToken = IERC20(_superToken);
        lastDifficultyAdjustment = block.timestamp;
    }
    
    /**
     * @notice 鐭垮伐娉ㄥ唽
     * @param _hashrate 鍒濆绠楀姏
     * @param _deviceId 璁惧 ID (閾句笅鏍囪瘑)
     */
    function registerMiner(uint256 _hashrate, string calldata _deviceId) external {
        require(_hashrate >= MIN_HASHRATE && _hashrate <= MAX_HASHRATE, "Invalid hashrate");
        require(!registeredMiners[msg.sender], "Miner already registered");
        require(bytes(_deviceId).length > 0, "Device ID required");
        
        miners[msg.sender] = Miner({
            hashrate: _hashrate,
            lastClaimed: block.timestamp,
            pendingReward: 0,
            totalClaimed: 0,
            registeredTime: block.timestamp,
            active: true,
            suspiciousScore: 0
        });
        
        registeredMiners[msg.sender] = true;
        totalMiners++;
        totalActiveHashrate += _hashrate;
        
        emit MinerRegistered(msg.sender, _hashrate);
    }
    
    /**
     * @notice 鏇存柊鎸栫熆绠楀姏
     * @param _newHashrate 鏂扮畻鍔?
     */
    function updateHashrate(uint256 _newHashrate) external {
        require(registeredMiners[msg.sender], "Miner not registered");
        require(_newHashrate >= MIN_HASHRATE && _newHashrate <= MAX_HASHRATE, "Invalid hashrate");
        
        Miner storage miner = miners[msg.sender];
        require(miner.active, "Miner not active");
        
        // 妫€娴嬪紓甯哥畻鍔涘彉鍖?(绂荤嚎鍚庣獊鐒舵彁鍗?
        if (_newHashrate > miner.hashrate * 2 && miner.lastClaimed + 1 days < block.timestamp) {
            miner.suspiciousScore += 10;
            emit SuspiciousActivityDetected(msg.sender, miner.suspiciousScore, "Sudden hashrate increase");
        }
        
        uint256 oldHashrate = miner.hashrate;
        totalActiveHashrate = totalActiveHashrate - oldHashrate + _newHashrate;
        miner.hashrate = _newHashrate;
        
        emit HashrateUpdated(msg.sender, oldHashrate, _newHashrate);
    }
    
    /**
     * @notice 璁＄畻寰呴鍙栧鍔?
     * @param _miner 鐭垮伐鍦板潃
     * @return 寰呴鍙栧鍔遍噾棰?
     */
    function calculatePendingReward(address _miner) public view returns (uint256) {
        require(registeredMiners[_miner], "Miner not registered");
        
        Miner storage miner = miners[_miner];
        if (!miner.active || miner.hashrate == 0) return miner.pendingReward;
        
        // 妫€鏌ラ攣浠撴湡
        if (block.timestamp < miner.registeredTime + lockupPeriod) {
            return miner.pendingReward;  // 閿佷粨鏈熷唴涓嶈绠楀鍔?
        }
        
        // 鏃堕棿宸?
        uint256 timePassed = block.timestamp - miner.lastClaimed;
        
        // 濂栧姳 = 鍏ㄥ眬鏃ヤ骇 * (璇ョ熆宸ョ畻鍔?/ 鍏ㄧ悆鎬荤畻鍔? * 鏃堕棿姣斾緥
        uint256 dailyGlobalReward = DAILY_EMISSION;
        uint256 minerShare = (dailyGlobalReward * miner.hashrate) / (totalActiveHashrate == 0 ? 1 : totalActiveHashrate);
        uint256 reward = (minerShare * timePassed) / (1 days);
        
        return miner.pendingReward + reward;
    }
    
    /**
     * @notice 棰嗗彇濂栧姳
     */
    function claimReward() external nonReentrant {
        require(registeredMiners[msg.sender], "Miner not registered");
        
        Miner storage miner = miners[msg.sender];
        require(miner.active, "Miner not active");
        
        // 妫€鏌ュ喎鍗?
        uint256 timeSinceLast = block.timestamp - miner.lastClaimed;
        require(timeSinceLast >= claimCooldown, "Claim cooldown not met");
        
        // 璁＄畻濂栧姳
        uint256 reward = calculatePendingReward(msg.sender);
        require(reward > 0, "No reward to claim");
        
        // 妫€娴嬩綔寮婅涓?
        if (timeSinceLast > 7 days && miner.hashrate > MIN_HASHRATE * 10) {
            // 7 澶╂湭棰嗗彇鍗存湁楂樼畻鍔?= 鍙枒
            miner.suspiciousScore += 5;
        }
        
        // 閲嶇疆寰呴鍙栧鍔卞拰鏈€鍚庨鍙栨椂闂?
        miner.pendingReward = 0;
        miner.lastClaimed = block.timestamp;
        miner.totalClaimed += reward;
        totalEmitted += reward;
        
        // 杞处 SUPER 浠ｅ竵
        require(superToken.transfer(msg.sender, reward), "Token transfer failed");
        
        emit RewardClaimed(msg.sender, reward);
    }
    
    /**
     * @notice 璋冩暣闅惧害 (瀹氭湡璋冪敤)
     */
    function adjustDifficulty() external onlyOwner {
        require(block.timestamp >= lastDifficultyAdjustment + difficultyAdjustmentPeriod, "Too early to adjust");
        
        globalHashrate = totalActiveHashrate;
        lastDifficultyAdjustment = block.timestamp;
        
        emit DifficultyAdjusted(globalHashrate);
    }
    
    /**
     * @notice 鏇存柊濂栧姳鍙傛暟 (浠?Owner)
     * @param _rewardPerHash 姣忓崟浣嶇畻鍔涚殑濂栧姳
     * @param _claimCooldown 鏂扮殑鍐峰嵈鏃堕棿
     */
    function updateRewardParameters(uint256 _rewardPerHash, uint256 _claimCooldown) external onlyOwner {
        rewardPerHashPerDay = _rewardPerHash;
        claimCooldown = _claimCooldown;
        
        emit RewardParametersUpdated(_rewardPerHash, _claimCooldown);
    }
    
    /**
     * @notice 鍋滅敤鐭垮伐 (寮傚父妫€娴?
     * @param _miner 鐭垮伐鍦板潃
     */
    function deactivateMiner(address _miner, string calldata _reason) external onlyOwner {
        require(registeredMiners[_miner], "Miner not registered");
        
        Miner storage miner = miners[_miner];
        require(miner.active, "Miner already inactive");
        
        miner.active = false;
        totalActiveHashrate -= miner.hashrate;
        
        emit MinerDeactivated(_miner, _reason);
    }
    
    /**
     * @notice 鑾峰彇鐭垮伐淇℃伅
     */
    function getMinerInfo(address _miner) external view returns (
        uint256 hashrate,
        uint256 pending,
        uint256 totalClaimed,
        bool active,
        uint256 suspiciousScore
    ) {
        require(registeredMiners[_miner], "Miner not registered");
        Miner storage miner = miners[_miner];
        return (
            miner.hashrate,
            calculatePendingReward(_miner),
            miner.totalClaimed,
            miner.active,
            miner.suspiciousScore
        );
    }
    
    /**
     * @notice 鑾峰彇鍏ㄥ眬缁熻
     */
    function getGlobalStats() external view returns (
        uint256 totalEm,
        uint256 totalActive,
        uint256 minerCount
    ) {
        return (totalEmitted, totalActiveHashrate, totalMiners);
    }
}

contracts/SUPER.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Permit.sol";

/**
 * @title SUPER Token
 * @notice MinerHub 鐢熸€佷唬甯侊紝鏀寔閾搁€犮€侀攢姣併€佹爣鍑?ERC20 鎿嶄綔
 */
contract SUPER is ERC20, ERC20Burnable, Ownable, ERC20Permit {
    // 浠ｅ竵鎬讳緵搴旈噺锛?0 浜?SUPER
    uint256 public constant TOTAL_SUPPLY = 1_000_000_000 * 10 ** 18;
    
    // 宸查摳閫犵殑浠ｅ竵鎬婚噺杩借釜
    uint256 public totalMinted;
    
    // 浜嬩欢
    event MinterAdded(address indexed minter);
    event MinterRemoved(address indexed minter);
    event TokensMinted(address indexed to, uint256 amount);
    event TokensBurned(address indexed from, uint256 amount);
    
    // 閾搁€犺€呮潈闄愭槧灏?
    mapping(address => bool) public minters;

    constructor() ERC20("MinerHub Token", "SUPER") ERC20Permit("MinerHub Token") {
        // 鍒濆渚涘簲缁欓儴缃茶€咃紙鐢ㄤ簬鍒濆鍖?Swap 姹犲拰鐢熸€佸熀閲戯級
        // 灏嗗湪閮ㄧ讲鑴氭湰涓垎閰嶅埌涓嶅悓鍦板潃
    }
    
    /**
     * @notice 娣诲姞閾搁€犺€呮潈闄愶紙浠?Owner锛?
     * @param _minter 閾搁€犺€呭湴鍧€
     */
    function addMinter(address _minter) external onlyOwner {
        require(_minter != address(0), "Invalid minter address");
        minters[_minter] = true;
        emit MinterAdded(_minter);
    }
    
    /**
     * @notice 绉婚櫎閾搁€犺€呮潈闄愶紙浠?Owner锛?
     * @param _minter 閾搁€犺€呭湴鍧€
     */
    function removeMinter(address _minter) external onlyOwner {
        require(minters[_minter], "Address is not a minter");
        minters[_minter] = false;
        emit MinterRemoved(_minter);
    }
    
    /**
     * @notice 閾搁€犳柊鐨?SUPER 浠ｅ竵锛堜粎閾搁€犺€呮垨 Owner锛?
     * @param _to 鎺ユ敹鍦板潃
     * @param _amount 閾搁€犳暟閲?
     */
    function mint(address _to, uint256 _amount) external {
        require(msg.sender == owner() || minters[msg.sender], "Only minter or owner can mint");
        require(_to != address(0), "Invalid recipient address");
        require(totalMinted + _amount <= TOTAL_SUPPLY, "Exceeds max supply");
        
        totalMinted += _amount;
        _mint(_to, _amount);
        emit TokensMinted(_to, _amount);
    }
    
    /**
     * @notice 閿€姣佷唬甯佺殑閲嶅啓锛堟坊鍔犱簨浠讹級
     * @param _amount 閿€姣佹暟閲?
     */
    function burn(uint256 _amount) public override {
        super.burn(_amount);
        emit TokensBurned(_msgSender(), _amount);
    }
    
    /**
     * @notice 浠庢寚瀹氬湴鍧€閿€姣佷唬甯佺殑閲嶅啓锛堟坊鍔犱簨浠讹級
     * @param _account 璐︽埛鍦板潃
     * @param _amount 閿€姣佹暟閲?
     */
    function burnFrom(address _account, uint256 _amount) public override {
        super.burnFrom(_account, _amount);
        emit TokensBurned(_account, _amount);
    }
    
    /**
     * @notice 鑾峰彇鍓╀綑鍙摳閫犱唬甯佹暟閲?
     * @return 鍓╀綑浠ｅ竵鏁伴噺
     */
    function remainingSupply() external view returns (uint256) {
        return TOTAL_SUPPLY - totalMinted;
    }
    
    /**
     * @notice 妫€鏌ュ湴鍧€鏄惁涓洪摳閫犺€?
     * @param _account 璐︽埛鍦板潃
     * @return 鏄惁涓洪摳閫犺€?
     */
    function isMinter(address _account) external view returns (bool) {
        return _account == owner() || minters[_account];
    }
}

contracts/SwapRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title SwapRouter
 * @notice MinerHub AMM (鑷姩鍋氬競鍟? - SUPER 鈫?USDT 浜ゆ崲
 * - 绠€鍗曠殑 x * y = k 妯″紡
 * - 鍒濆娴佸姩鎬э細50M SUPER + 50k USDT
 * - 鎵嬬画璐癸細0.5% (70% LP, 20% 骞冲彴, 10% 鐢熸€?
 */
contract SwapRouter is Ownable, ReentrancyGuard {
    IERC20 public superToken;
    IERC20 public usdtToken;
    
    // 娴佸姩鎬ф睜
    uint256 public reserveSuper;
    uint256 public reserveUSDT;
    
    // 鎵嬬画璐瑰弬鏁?
    uint256 public constant FEE_BIPS = 50;  // 0.5% = 50 basis points
    uint256 public lpFeeShare = 70;         // LP 鑾峰緱 70%
    uint256 public platformFeeShare = 20;   // 骞冲彴 20%
    uint256 public ecosystemFeeShare = 10;  // 鐢熸€?10%
    
    // 娴佸姩鎬ф彁渚涜€?(LP) 杩借釜
    mapping(address => uint256) public lpShares;
    uint256 public totalLPShares;
    
    // 鎵嬬画璐圭Н绱?
    uint256 public accumulatedPlatformFee;
    uint256 public accumulatedEcosystemFee;
    
    // 浠锋牸鍘嗗彶
    struct PricePoint {
        uint256 timestamp;
        uint256 priceSuperPerUSDT;  // SUPER 浠锋牸 (鐩稿 USDT锛岀簿搴?18)
    }
    PricePoint[] public priceHistory;
    
    // 浜嬩欢
    event LiquidityAdded(address indexed provider, uint256 superAmount, uint256 usdtAmount, uint256 sharesIssued);
    event LiquidityRemoved(address indexed provider, uint256 superAmount, uint256 usdtAmount, uint256 sharesBurned);
    event Swap(address indexed user, bool isSuperToUsdt, uint256 inputAmount, uint256 outputAmount, uint256 feeAmount);
    event FeeCollected(uint256 platformFee, uint256 ecosystemFee);
    event PriceUpdated(uint256 priceSuperPerUSDT);
    
    constructor(address _super, address _usdt) {
        require(_super != address(0) && _usdt != address(0), "Invalid token addresses");
        superToken = IERC20(_super);
        usdtToken = IERC20(_usdt);
    }
    
    /**
     * @notice 鍒濆鍖栨祦鍔ㄦ€ф睜 (浠?Owner锛屽彧鑳借皟鐢ㄤ竴娆?
     * @param _superAmount SUPER 浠ｅ竵鏁伴噺
     * @param _usdtAmount USDT 鏁伴噺
     */
    function initializeLiquidity(uint256 _superAmount, uint256 _usdtAmount) external onlyOwner nonReentrant {
        require(reserveSuper == 0 && reserveUSDT == 0, "Liquidity already initialized");
        require(_superAmount > 0 && _usdtAmount > 0, "Invalid amounts");
        
        // 浠?Owner 杞处浠ｅ竵
        require(superToken.transferFrom(msg.sender, address(this), _superAmount), "SUPER transfer failed");
        require(usdtToken.transferFrom(msg.sender, address(this), _usdtAmount), "USDT transfer failed");
        
        reserveSuper = _superAmount;
        reserveUSDT = _usdtAmount;
        
        // 鍒濆 LP 浠介
        uint256 issuedShares = _sqrt(_superAmount * _usdtAmount);
        lpShares[msg.sender] = issuedShares;
        totalLPShares = issuedShares;
        
        emit LiquidityAdded(msg.sender, _superAmount, _usdtAmount, issuedShares);
        _recordPrice();
    }
    
    /**
     * @notice 娣诲姞娴佸姩鎬?
     * @param _superAmount SUPER 浠ｅ竵鏁伴噺
     * @param _usdtAmount USDT 鏁伴噺
     */
    function addLiquidity(uint256 _superAmount, uint256 _usdtAmount) external nonReentrant {
        require(_superAmount > 0 && _usdtAmount > 0, "Invalid amounts");
        require(reserveSuper > 0 && reserveUSDT > 0, "No initial liquidity");
        
        // 杞处浠ｅ竵
        require(superToken.transferFrom(msg.sender, address(this), _superAmount), "SUPER transfer failed");
        require(usdtToken.transferFrom(msg.sender, address(this), _usdtAmount), "USDT transfer failed");
        
        // 璁＄畻鏂板 LP 浠介
        uint256 superShare = (_superAmount * totalLPShares) / reserveSuper;
        uint256 usdtShare = (_usdtAmount * totalLPShares) / reserveUSDT;
        uint256 newShares = superShare < usdtShare ? superShare : usdtShare;
        
        reserveSuper += _superAmount;
        reserveUSDT += _usdtAmount;
        lpShares[msg.sender] += newShares;
        totalLPShares += newShares;
        
        emit LiquidityAdded(msg.sender, _superAmount, _usdtAmount, newShares);
        _recordPrice();
    }
    
    /**
     * @notice 绉婚櫎娴佸姩鎬?
     * @param _sharesToBurn 瑕侀攢姣佺殑 LP 浠介
     */
    function removeLiquidity(uint256 _sharesToBurn) external nonReentrant {
        require(_sharesToBurn > 0 && lpShares[msg.sender] >= _sharesToBurn, "Invalid shares");
        
        // 璁＄畻鍙彁鍙栫殑浠ｅ竵鏁伴噺
        uint256 superAmount = (reserveSuper * _sharesToBurn) / totalLPShares;
        uint256 usdtAmount = (reserveUSDT * _sharesToBurn) / totalLPShares;
        
        require(superAmount > 0 && usdtAmount > 0, "Insufficient liquidity");
        
        // 鏇存柊姹犲拰浠介
        reserveSuper -= superAmount;
        reserveUSDT -= usdtAmount;
        lpShares[msg.sender] -= _sharesToBurn;
        totalLPShares -= _sharesToBurn;
        
        // 杞处浠ｅ竵
        require(superToken.transfer(msg.sender, superAmount), "SUPER transfer failed");
        require(usdtToken.transfer(msg.sender, usdtAmount), "USDT transfer failed");
        
        emit LiquidityRemoved(msg.sender, superAmount, usdtAmount, _sharesToBurn);
        _recordPrice();
    }
    
    /**
     * @notice SUPER 鈫?USDT 浜ゆ崲
     * @param _superAmount SUPER 鏁伴噺
     * @return usdtAmount 鑾峰緱鐨?USDT 鏁伴噺
     */
    function swapSuperToUsdt(uint256 _superAmount) external nonReentrant returns (uint256) {
        require(_superAmount > 0, "Invalid amount");
        
        // 璁＄畻杈撳嚭 (鑰冭檻鎵嬬画璐?
        uint256 amountWithoutFee = _superAmount * (10000 - FEE_BIPS) / 10000;
        uint256 usdtAmount = _getAmountOut(amountWithoutFee, reserveSuper, reserveUSDT);
        
        require(usdtAmount > 0, "Insufficient liquidity");
        
        // 杞处杈撳叆
        require(superToken.transferFrom(msg.sender, address(this), _superAmount), "SUPER transfer failed");
        
        // 璁＄畻鎵嬬画璐?
        uint256 totalFee = _superAmount - amountWithoutFee;
        uint256 lpFee = (totalFee * lpFeeShare) / 100;
        uint256 platformFee = (totalFee * platformFeeShare) / 100;
        uint256 ecosystemFee = totalFee - lpFee - platformFee;
        
        // 鏇存柊姹?
        reserveSuper += _superAmount - lpFee;  // LP 璐圭敤 LP 鍒嗕韩
        reserveUSDT -= usdtAmount;
        
        accumulatedPlatformFee += platformFee;
        accumulatedEcosystemFee += ecosystemFee;
        
        // 杞处杈撳嚭
        require(usdtToken.transfer(msg.sender, usdtAmount), "USDT transfer failed");
        
        emit Swap(msg.sender, true, _superAmount, usdtAmount, totalFee);
        _recordPrice();
        
        return usdtAmount;
    }
    
    /**
     * @notice USDT 鈫?SUPER 浜ゆ崲
     * @param _usdtAmount USDT 鏁伴噺
     * @return superAmount 鑾峰緱鐨?SUPER 鏁伴噺
     */
    function swapUsdtToSuper(uint256 _usdtAmount) external nonReentrant returns (uint256) {
        require(_usdtAmount > 0, "Invalid amount");
        
        // 璁＄畻杈撳嚭 (鑰冭檻鎵嬬画璐?
        uint256 amountWithoutFee = _usdtAmount * (10000 - FEE_BIPS) / 10000;
        uint256 superAmount = _getAmountOut(amountWithoutFee, reserveUSDT, reserveSuper);
        
        require(superAmount > 0, "Insufficient liquidity");
        
        // 杞处杈撳叆
        require(usdtToken.transferFrom(msg.sender, address(this), _usdtAmount), "USDT transfer failed");
        
        // 璁＄畻鎵嬬画璐?
        uint256 totalFee = _usdtAmount - amountWithoutFee;
        uint256 lpFee = (totalFee * lpFeeShare) / 100;
        uint256 platformFee = (totalFee * platformFeeShare) / 100;
        uint256 ecosystemFee = totalFee - lpFee - platformFee;
        
        // 鏇存柊姹?
        reserveUSDT += _usdtAmount - lpFee;
        reserveSuper -= superAmount;
        
        accumulatedPlatformFee += platformFee;
        accumulatedEcosystemFee += ecosystemFee;
        
        // 杞处杈撳嚭
        require(superToken.transfer(msg.sender, superAmount), "SUPER transfer failed");
        
        emit Swap(msg.sender, false, _usdtAmount, superAmount, totalFee);
        _recordPrice();
        
        return superAmount;
    }
    
    /**
     * @notice 鑾峰彇 SUPER/USDT 浠锋牸
     */
    function getPrice() external view returns (uint256) {
        if (reserveUSDT == 0) return 0;
        return (reserveSuper * 1e18) / reserveUSDT;
    }
    
    /**
     * @notice 鎻愬彇骞冲彴鎵嬬画璐?(浠?Owner)
     */
    function collectPlatformFee() external onlyOwner nonReentrant {
        uint256 fee = accumulatedPlatformFee;
        require(fee > 0, "No fee to collect");
        accumulatedPlatformFee = 0;
        require(superToken.transfer(msg.sender, fee), "Transfer failed");
        emit FeeCollected(fee, 0);
    }
    
    /**
     * @notice 鎻愬彇鐢熸€佸熀閲?(浠?Owner)
     */
    function collectEcosystemFee(address _recipient) external onlyOwner nonReentrant {
        uint256 fee = accumulatedEcosystemFee;
        require(fee > 0, "No fee to collect");
        accumulatedEcosystemFee = 0;
        require(superToken.transfer(_recipient, fee), "Transfer failed");
        emit FeeCollected(0, fee);
    }
    
    // ========== 鍐呴儴鍑芥暟 ==========
    
    /**
     * @notice 璁＄畻 AMM 杈撳嚭 (x * y = k)
     */
    function _getAmountOut(uint256 amountIn, uint256 reserveIn, uint256 reserveOut) internal pure returns (uint256) {
        uint256 k = reserveIn * reserveOut;
        uint256 newReserveIn = reserveIn + amountIn;
        uint256 newReserveOut = k / newReserveIn;
        return reserveOut - newReserveOut;
    }
    
    /**
     * @notice 寮€骞虫柟鏍?(鐢ㄤ簬娴佸姩鎬ц绠?
     */
    function _sqrt(uint256 x) internal pure returns (uint256) {
        if (x == 0) return 0;
        uint256 xx = x;
        uint256 r = 1;
        if (xx >= 0x100000000000000000000000000000000) { xx >>= 128; r <<= 64; }
        if (xx >= 0x10000000000000000) { xx >>= 64; r <<= 32; }
        if (xx >= 0x100000000) { xx >>= 32; r <<= 16; }
        if (xx >= 0x10000) { xx >>= 16; r <<= 8; }
        if (xx >= 0x100) { xx >>= 8; r <<= 4; }
        if (xx >= 0x10) { xx >>= 4; r <<= 2; }
        if (xx >= 0x8) r <<= 1;
        r = (r + x / r) >> 1;
        r = (r + x / r) >> 1;
        r = (r + x / r) >> 1;
        r = (r + x / r) >> 1;
        r = (r + x / r) >> 1;
        r = (r + x / r) >> 1;
        r = (r + x / r) >> 1;
        uint256 r1 = x / r;
        return r < r1 ? r : r1;
    }
    
    /**
     * @notice 璁板綍浠锋牸鍘嗗彶
     */
    function _recordPrice() internal {
        uint256 price = (reserveSuper * 1e18) / (reserveUSDT == 0 ? 1 : reserveUSDT);
        priceHistory.push(PricePoint({
            timestamp: block.timestamp,
            priceSuperPerUSDT: price
        }));
        
        // 鍙繚鐣欐渶杩?1000 鏉¤褰?
        if (priceHistory.length > 1000) {
            for (uint256 i = 0; i < priceHistory.length - 1; i++) {
                priceHistory[i] = priceHistory[i + 1];
            }
            priceHistory.pop();
        }
        
        emit PriceUpdated(price);
    }
}

